mapper.insert:
INSERT INTO TB_DOMAIN
(
 DOMAIN_ID
 ,DOMAIN_NM			
 ,DOMAIN_GRP_NM
 ,DOMAIN_CLSF_NM		
 ,DOMAIN_DESC		
 ,DATA_TYPE	
 ,DATA_LEN
 ,DATA_DECIMAL_LEN	
 ,DATA_UNIT
 ,STOR_FMT 		
 ,EXPR_FMT_LST			
 ,ALLOW_VAL_LST	
 ,COMM_STND_YN	
 ,MAGNTD_ORD		
 ,APRV_YN			
 ,APRV_USER_ID	
 ,CRET_DT			
 ,CRET_USER_ID	
 ,APRV_STAT_UPDT_DT
 ,REQ_SYS_CD
)
VALUES
(
  #{id}
 ,#{domainNm}
 ,#{domainGrpNm}
 ,#{domainClsfNm}
 ,#{domainDesc}
 ,#{dataType}
 ,#{dataLen, jdbcType=SMALLINT}
 ,#{dataDecimalLen, jdbcType=SMALLINT}
 ,#{dataUnit, jdbcType=VARCHAR}
 ,#{storFmt, jdbcType=VARCHAR}
 ,#{exprFmtLst, typeHandler=com.ndata.common.handler.ArrayTypeHandler}
 ,#{allowValLst, typeHandler=com.ndata.common.handler.ArrayTypeHandler}
 ,#{commStndYn, jdbcType=VARCHAR}
 ,#{magntdOrd, jdbcType=VARCHAR}
 ,#{aprvYn, jdbcType=VARCHAR}
 ,#{aprvUserId, jdbcType=VARCHAR}
 ,to_char(now(), 'YYYYMMDDHH24MISS')
 ,#{cretUserId, jdbcType=VARCHAR}
 ,to_char(now(), 'YYYYMMDDHH24MISS')
 ,#{reqSysCd, jdbcType=VARCHAR}
)

mapper.update:
            UPDATE
              TB_DOMAIN
            SET
               DOMAIN_NM = #{domainNm}
              ,DOMAIN_GRP_NM = #{domainGrpNm}
              ,DOMAIN_CLSF_NM = #{domainClsfNm}
              ,DOMAIN_DESC = #{domainDesc}
              ,DATA_TYPE = #{dataType}
			        ,DATA_LEN = #{dataLen}
              ,DATA_DECIMAL_LEN = #{dataDecimalLen}
              ,DATA_UNIT = #{dataUnit, jdbcType=VARCHAR}
              ,STOR_FMT = #{storFmt, jdbcType=VARCHAR}
              ,EXPR_FMT_LST = #{exprFmtLst, typeHandler=com.ndata.common.handler.ArrayTypeHandler}
              ,ALLOW_VAL_LST = #{allowValLst, typeHandler=com.ndata.common.handler.ArrayTypeHandler}
              ,COMM_STND_YN = #{commStndYn, jdbcType=VARCHAR}
              ,MAGNTD_ORD = #{magntdOrd, jdbcType=VARCHAR}
              ,UPDT_DT = to_char(now(), 'YYYYMMDDHH24MISS')
              ,UPDT_USER_ID = #{updtUserId}
              ,REQ_SYS_CD = #{reqSysCd, jdbcType=VARCHAR}
            WHERE
              DOMAIN_ID = #{id}

